import{_ as o,o as l,c as i,ae as c}from"./chunks/framework.CF3ehLaw.js";const p=JSON.parse('{"title":"ROS2 Native Humble Migration Notes","description":"","frontmatter":{},"headers":[],"relativePath":"ROS2_NATIVE_HUMBLE_CHANGELOG.md","filePath":"ROS2_NATIVE_HUMBLE_CHANGELOG.md"}'),d={name:"ROS2_NATIVE_HUMBLE_CHANGELOG.md"};function r(a,e,t,s,_,u){return l(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="ros2-native-humble-migration-notes" tabindex="-1">ROS2 Native Humble Migration Notes <a class="header-anchor" href="#ros2-native-humble-migration-notes" aria-label="Permalink to &quot;ROS2 Native Humble Migration Notes&quot;">​</a></h1><p>本次修改目标：PC 和开发板都已经安装 ROS2 Humble 后，项目默认不再依赖 Docker Humble bridge，直接使用本机 ROS2 通讯。</p><h2 id="运行链路调整" tabindex="-1">运行链路调整 <a class="header-anchor" href="#运行链路调整" aria-label="Permalink to &quot;运行链路调整&quot;">​</a></h2><ul><li><p><code>src/mcp/tools/robot_dispatch/tools.py</code></p><ul><li><code>drone.takeoff</code> / <code>drone.land</code> 不再调用 <code>scripts/docker_humble_bridge.py pub-int</code>。</li><li>现在直接后台启动 <code>scripts/ros2_int32_publisher.py</code>，向 <code>/drone_command</code> 发布 <code>std_msgs/UInt8</code> 指令码。</li><li>指令码保持不变：<code>1</code> 起飞，<code>2</code> 降落，<code>3</code> 紧急降落。</li></ul></li><li><p><code>scripts/ros2_int32_publisher.py</code></p><ul><li>增加本机 ROS2 环境自动探测。</li><li>即使终端没有手动 <code>source /opt/ros/humble/setup.bash</code>，脚本也会尝试通过 <code>/opt/ros/&lt;distro&gt;</code> 补齐 <code>rclpy</code> 环境。</li><li>节点名从 <code>docker_uint8_publisher</code> 改为 <code>aiagent_uint8_publisher</code>。</li></ul></li><li><p><code>scripts/ros2_string_publisher.py</code></p><ul><li>增加本机 ROS2 环境自动探测。</li><li>节点名从 <code>docker_string_publisher</code> 改为 <code>aiagent_string_publisher</code>。</li></ul></li><li><p><code>scripts/ros2_action_client.py</code></p><ul><li>增加本机 ROS2 环境自动探测，便于直接使用本机 Humble action client。</li></ul></li><li><p><code>src/utils/ros2_env.py</code></p><ul><li>ROS2 Python 包探测兼容 Ubuntu 常见的 <code>local/lib/python*/dist-packages</code>。</li><li><code>reexec=True</code> 时会用补齐后的 ROS2 环境重启当前脚本，确保 <code>PYTHONPATH</code> 和 <code>LD_LIBRARY_PATH</code> 在进程启动阶段生效。</li></ul></li></ul><h2 id="启动脚本调整" tabindex="-1">启动脚本调整 <a class="header-anchor" href="#启动脚本调整" aria-label="Permalink to &quot;启动脚本调整&quot;">​</a></h2><ul><li><p><code>scripts/run_local_action_agent.sh</code></p><ul><li>默认 <code>ROS2_PUBLISH_MODE=auto</code>。</li><li>删除默认启动 Docker bridge 的步骤。</li><li>启动前会 source <code>/opt/ros/humble/setup.bash</code>。</li><li>如果存在 <code>${ROS2_HUMBLE_HOST_WS}/install/setup.bash</code>，也会自动 source overlay 工作区。</li></ul></li><li><p><code>scripts/run_robot_action_demo_server.sh</code></p><ul><li>默认 <code>ROS2_PUBLISH_MODE=auto</code>。</li><li>删除 Docker bridge 启动、容器内构建、容器内运行 demo server。</li><li>现在直接在本机 <code>${ROS2_HUMBLE_HOST_WS}</code> 下 <code>colcon build</code>，然后 <code>ros2 run robot_action_demo dispatch_server</code>。</li></ul></li></ul><h2 id="测试脚本调整" tabindex="-1">测试脚本调整 <a class="header-anchor" href="#测试脚本调整" aria-label="Permalink to &quot;测试脚本调整&quot;">​</a></h2><ul><li><p><code>scripts/test_ros2_e2e.sh</code></p><ul><li>默认 ROS 发行版从 <code>jazzy</code> 改为 <code>humble</code>。</li></ul></li><li><p><code>scripts/test_ros2_official_examples.sh</code></p><ul><li>默认 ROS 发行版从 <code>jazzy</code> 改为 <code>humble</code>。</li></ul></li></ul><h2 id="仍然保留的-docker-文件" tabindex="-1">仍然保留的 Docker 文件 <a class="header-anchor" href="#仍然保留的-docker-文件" aria-label="Permalink to &quot;仍然保留的 Docker 文件&quot;">​</a></h2><ul><li><code>scripts/docker_humble_bridge.py</code> 暂时保留。 <ul><li>它现在不是默认运行链路。</li><li>如果以后又遇到 PC 和开发板 ROS2 版本不一致，仍可临时切回 Docker bridge。</li></ul></li></ul><h2 id="markdown-文件整理" tabindex="-1">Markdown 文件整理 <a class="header-anchor" href="#markdown-文件整理" aria-label="Permalink to &quot;Markdown 文件整理&quot;">​</a></h2><p>项目根目录原有 Markdown 文件已移动到 <code>project_markdown/</code>：</p><ul><li><code>README.md</code></li><li><code>README.en.md</code></li><li><code>ROS2_DEBUG_NOTES.md</code></li><li><code>DRONE_AGENT_GUIDE.md</code></li><li><code>MAPPING_VIEW_FEATURE_PLAN.md</code></li><li><code>WEB_UI_ARCHITECTURE_PLAN.md</code></li></ul><p>以后新增项目说明、调试记录、方案设计类 Markdown，建议统一放在 <code>project_markdown/</code>。</p>',14)])])}const h=o(d,[["render",r]]);export{p as __pageData,h as default};
